// Generate Personalized Learning Path
const assessment = JSON.parse($('AI Level Assessment').first().json.message.content);
const student = $('Student Registration Webhook').first().json;

return [{
  json: {
    student_id: 'STU-' + Date.now(),
    student_name: student.student_name,
    email: student.email,
    current_level: assessment.current_level,
    recommended_modules: assessment.recommended_modules,
    learning_style: assessment.learning_style,
    estimated_days: assessment.estimated_completion_days,
    risk_factors: assessment.risk_factors,
    current_module_index: 0,
    status: 'active',
    enrollment_date: $now.toISO()
  }
}];

