parameters.jsCode:
// Update Progress and Check Risk
const grading = JSON.parse($('AI Quiz Grading').first().json.message.content);
const quizData = $('Quiz Submission Webhook').first().json;

let status = 'active';
let is_at_risk = false;

if (grading.score < 50) {
  is_at_risk = true;
  status = 'at_risk';
} else if (grading.passed) {
  status = 'module_completed';
}

return [{
  json: {
    ...quizData,
    score: grading.score,
    passed: grading.passed,
    feedback: grading.feedback,
    weak_areas: grading.weak_areas,
    status: status,
    is_at_risk: is_at_risk,
    graded_at: $now.toISO()
  }
}];

